solutions.javascript:
// Solution
function redirectMiddleware(request, response, next) {
    const redirectUrl = JSON.parse(request.body).redirectUrl;
    if (request.method === 'GET' && redirectUrl) {
        response.redirect(redirectUrl);
    } else {
        next();
    }
}

app.get('/', redirectMiddleware);
